-- Atualizar Aula 1: Variáveis e Tipos
UPDATE lessons SET 
  content = '<h2>Variáveis e Tipos de Dados em JavaScript</h2>
<p>JavaScript é uma linguagem dinamicamente tipada, o que significa que as variáveis podem mudar de tipo em tempo de execução. Entender os tipos de dados é fundamental para escrever código seguro e eficiente.</p>

<h3>Declaração de Variáveis</h3>
<p>Existem três formas de declarar variáveis em JavaScript:</p>
<ul>
<li><strong>var:</strong> Escopo de função, pode ser redeclarada, hoisting</li>
<li><strong>let:</strong> Escopo de bloco, não pode ser redeclarada, sem hoisting</li>
<li><strong>const:</strong> Escopo de bloco, não pode ser reatribuída, sem hoisting</li>
</ul>

<h3>Tipos Primitivos</h3>
<p><strong>String:</strong> Texto entre aspas simples, duplas ou template literals</p>
<pre><code>const nome = "João";
const saudacao = `Olá, ${nome}!`;</code></pre>

<p><strong>Number:</strong> Inteiros e decimais (sem distinção)</p>
<pre><code>const idade = 25;
const altura = 1.75;
const infinito = Infinity;</code></pre>

<p><strong>Boolean:</strong> true ou false</p>
<pre><code>const ativo = true;
const admin = false;</code></pre>

<p><strong>Null e Undefined:</strong> Valores especiais</p>
<pre><code>let valor = null; // Atribuído explicitamente
let indefinido; // Não inicializado = undefined</code></pre>

<p><strong>Symbol:</strong> Identificadores únicos</p>
<pre><code>const id = Symbol("id");
const id2 = Symbol("id"); // Diferente de id</code></pre>

<h3>Tipos Complexos</h3>
<p><strong>Object:</strong> Coleção de pares chave-valor</p>
<pre><code>const usuario = {
  nome: "Maria",
  idade: 30,
  ativo: true
};</code></pre>

<p><strong>Array:</strong> Lista ordenada de valores</p>
<pre><code>const cores = ["vermelho", "verde", "azul"];
const numeros = [1, 2, 3, 4, 5];</code></pre>

<h3>Conversão de Tipos</h3>
<p>JavaScript converte tipos automaticamente (coerção), mas você também pode fazer conversão explícita:</p>
<pre><code>// Conversão explícita
const numero = Number("42"); // 42
const texto = String(42); // "42"
const booleano = Boolean(1); // true

// Coerção automática
"5" + 3; // "53" (concatenação)
"5" - 3; // 2 (subtração numérica)</code></pre>

<h3>Na Prática</h3>
<p>Sempre use <code>const</code> por padrão, <code>let</code> quando precisar reatribuir, e evite <code>var</code>. Isso evita bugs relacionados a escopo e hoisting.</p>',
  video_url = 'https://www.youtube.com/embed/W6NZfCO5tTE'
WHERE module_id = @js_module AND title = 'Variáveis e Tipos';

-- Atualizar Aula 2: Operadores e Expressões
UPDATE lessons SET 
  content = '<h2>Operadores e Expressões em JavaScript</h2>
<p>Operadores são símbolos que realizam operações em valores. Dominar operadores é essencial para criar lógica de programação eficaz.</p>

<h3>Operadores Aritméticos</h3>
<pre><code>10 + 5;   // 15 (adição)
10 - 5;   // 5 (subtração)
10 * 5;   // 50 (multiplicação)
10 / 5;   // 2 (divisão)
10 % 3;   // 1 (módulo/resto)
2 ** 3;   // 8 (exponenciação)</code></pre>

<h3>Operadores de Atribuição</h3>
<pre><code>let x = 10;
x += 5;   // x = 15 (x = x + 5)
x -= 3;   // x = 12 (x = x - 3)
x *= 2;   // x = 24 (x = x * 2)
x /= 4;   // x = 6 (x = x / 4)</code></pre>

<h3>Operadores de Comparação</h3>
<pre><code>5 == "5";    // true (igualdade com coerção)
5 === "5";   // false (igualdade estrita)
5 != "5";    // false (desigualdade)
5 !== "5";   // true (desigualdade estrita)
5 > 3;       // true
5 >= 5;      // true
3 < 5;       // true</code></pre>

<h3>Operadores Lógicos</h3>
<pre><code>true && false;  // false (AND lógico)
true || false;  // true (OR lógico)
!true;          // false (NOT lógico)</code></pre>

<h3>Operador Ternário</h3>
<pre><code>const idade = 20;
const status = idade >= 18 ? "adulto" : "menor";
// status = "adulto"</code></pre>

<h3>Operadores de Tipo</h3>
<pre><code>typeof 42;           // "number"
typeof "texto";      // "string"
typeof true;         // "boolean"
typeof undefined;    // "undefined"
typeof {};           // "object"
typeof [];           // "object" (arrays são objetos)
typeof null;         // "object" (bug histórico)</code></pre>

<h3>Precedência de Operadores</h3>
<p>Operadores têm precedência (ordem de execução). Use parênteses para deixar claro:</p>
<pre><code>2 + 3 * 4;    // 14 (multiplicação primeiro)
(2 + 3) * 4;  // 20 (adição primeiro)</code></pre>

<h3>Na Prática</h3>
<p>Sempre use === em vez de == para evitar comportamentos inesperados. Entenda a precedência de operadores para evitar bugs lógicos.</p>',
  video_url = 'https://www.youtube.com/embed/fsVL3agtiRE'
WHERE module_id = @js_module AND title = 'Operadores e Expressões';

-- Atualizar Aula 3: Funções Avançadas
UPDATE lessons SET 
  content = '<h2>Funções Avançadas em JavaScript</h2>
<p>Funções são blocos de código reutilizáveis. JavaScript oferece várias formas de definir e usar funções, cada uma com seus próprios benefícios.</p>

<h3>Declaração de Funções</h3>
<pre><code>// Declaração de função
function saudar(nome) {
  return `Olá, ${nome}!`;
}

// Expressão de função
const saudar = function(nome) {
  return `Olá, ${nome}!`;
};

// Arrow function (ES6)
const saudar = (nome) => `Olá, ${nome}!`;</code></pre>

<h3>Parâmetros Padrão</h3>
<pre><code>function criar(titulo = "Sem Título", descricao = "") {
  return { titulo, descricao };
}

criar(); // { titulo: "Sem Título", descricao: "" }
criar("Novo Item"); // { titulo: "Novo Item", descricao: "" }</code></pre>

<h3>Rest Parameters</h3>
<pre><code>function somar(...numeros) {
  return numeros.reduce((a, b) => a + b, 0);
}

somar(1, 2, 3, 4, 5); // 15</code></pre>

<h3>Closures</h3>
<p>Uma closure é uma função que tem acesso às variáveis da função externa mesmo após ela ter retornado.</p>
<pre><code>function criar_contador() {
  let count = 0;
  return function() {
    return ++count;
  };
}

const contador = criar_contador();
contador(); // 1
contador(); // 2
contador(); // 3</code></pre>

<h3>Callbacks</h3>
<pre><code>function processar(dados, callback) {
  const resultado = dados.map(x => x * 2);
  callback(resultado);
}

processar([1, 2, 3], (resultado) => {
  console.log(resultado); // [2, 4, 6]
});</code></pre>

<h3>Promises</h3>
<pre><code>const promise = new Promise((resolve, reject) => {
  setTimeout(() => {
    resolve("Sucesso!");
  }, 1000);
});

promise.then(resultado => {
  console.log(resultado); // "Sucesso!"
});</code></pre>

<h3>Async/Await</h3>
<pre><code>async function buscar_dados() {
  try {
    const resposta = await fetch("/api/dados");
    const dados = await resposta.json();
    return dados;
  } catch (erro) {
    console.error("Erro:", erro);
  }
}</code></pre>

<h3>Na Prática</h3>
<p>Use arrow functions para callbacks, evite callbacks aninhados (callback hell), e prefira async/await para código assíncrono mais legível.</p>',
  video_url = 'https://www.youtube.com/embed/FOD408a7EQE'
WHERE module_id = @js_module AND title = 'Funções Avançadas';

SELECT COUNT(*) as aulas_atualizadas FROM lessons WHERE module_id = @js_module;

